      "keystrokes": "cat <<'EOF' > /app/visualize.sh
dot -Tpng /app/dialogue.dot -o /app/dialogue.png
echo 'Visualization generated at /app/dialogue.png'
EOF",
      "duration": 0.1
    },
    {
